// Greenery + Pearl 2025 by Delightful Designs
// Green Treeline: #478559
// Purple baseline: #161748
// Grey Blue Leaf: #4f5f76
// Pearl/Cream: #f5f0e8, #faf7f2
// Accents derived from palette

export const C = {
  // Primary palette - exact from scheme
  green:      '#478559',
  greenDark:  '#2d5c3d',
  greenLight: '#6aab7e',
  purple:     '#161748',
  purpleMid:  '#232466',
  greyBlue:   '#4f5f76',
  greyBlueLight: '#7a8fa6',

  // Pearl/Cream backgrounds
  pearl:      '#f5f0e8',
  pearlDark:  '#ede5d8',
  cream:      '#faf7f2',
  white:      '#ffffff',

  // Text
  textDark:   '#161748',
  textMid:    '#4f5f76',
  textLight:  '#8a9ab0',

  // Functional
  success:    '#478559',
  warning:    '#b07d2a',
  error:      '#8b2635',
  info:       '#4f5f76',

  // Card backgrounds
  cardBg:     '#ffffff',
  cardBorder: 'rgba(71,133,89,0.15)',

  // Gradients
  sidebarGrad: 'linear-gradient(180deg, #161748 0%, #232466 55%, #4f5f76 100%)',
  heroGrad:    'linear-gradient(135deg, #161748 0%, #232466 60%, #4f5f76 100%)',
  greenGrad:   'linear-gradient(135deg, #478559 0%, #2d5c3d 100%)',
};
